import { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { patientAPI, commonAPI } from '../../utils/api';
import { useApp } from '../../context/AppContext';
import toast from 'react-hot-toast';

export default function FindDoctors() {
  const { patientId } = useApp();
  const [searchParams] = useSearchParams();
  const [doctors, setDoctors] = useState([]);
  const [specializations, setSpecializations] = useState([]);
  const [selectedSpec, setSelectedSpec] = useState('');
  const [loading, setLoading] = useState(true);

  // Booking state
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [selectedDate, setSelectedDate] = useState('');
  const [slots, setSlots] = useState([]);
  const [selectedSlot, setSelectedSlot] = useState('');
  const [reason, setReason] = useState('');
  const [booking, setBooking] = useState(false);
  const [slotsLoading, setSlotsLoading] = useState(false);

  useEffect(() => {
    commonAPI.getSpecializations().then(r => setSpecializations(r.data)).catch(() => {});
    const specParam = searchParams.get('specialization');
    if (specParam) setSelectedSpec(specParam);
  }, []);

  useEffect(() => { loadDoctors(); }, [selectedSpec]);

  const loadDoctors = async () => {
    setLoading(true);
    try {
      const spec = specializations.find(s => s.name === selectedSpec);
      const res = await patientAPI.getDoctors(spec?.id);
      setDoctors(res.data);
    } catch { toast.error('Failed to load doctors'); }
    finally { setLoading(false); }
  };

  const openBooking = (doctor) => {
    if (!patientId) { toast.error('Please set up your profile first'); return; }
    setSelectedDoctor(doctor);
    setSelectedDate('');
    setSlots([]);
    setSelectedSlot('');
    setReason('');
    setShowModal(true);
  };

  const handleDateChange = async (date) => {
    setSelectedDate(date);
    setSelectedSlot('');
    if (!date) return;
    setSlotsLoading(true);
    try {
      const res = await patientAPI.getSlots(selectedDoctor.id, date);
      setSlots(res.data);
    } catch { toast.error('Failed to load slots'); }
    finally { setSlotsLoading(false); }
  };

  const handleBook = async () => {
    if (!selectedDate || !selectedSlot) { toast.error('Please select a date and time'); return; }
    setBooking(true);
    try {
      await patientAPI.bookAppointment({
        patient_id: patientId,
        doctor_id: selectedDoctor.id,
        appointment_date: selectedDate,
        appointment_time: selectedSlot,
        reason
      });
      toast.success('Appointment booked successfully! 🎉');
      setShowModal(false);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Booking failed');
    } finally { setBooking(false); }
  };

  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 6 }}>👨‍⚕️ Find Doctors</h1>
        <p style={{ color: 'var(--text-muted)' }}>Browse available doctors and book your appointment</p>
      </div>

      {/* Filter */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-body" style={{ paddingTop: 16, paddingBottom: 16 }}>
          <div style={{ display: 'flex', gap: 12, alignItems: 'center', flexWrap: 'wrap' }}>
            <select className="form-control" style={{ maxWidth: 280 }}
              value={selectedSpec}
              onChange={e => setSelectedSpec(e.target.value)}>
              <option value="">All Specializations</option>
              {specializations.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
            </select>
            {selectedSpec && (
              <button className="btn btn-outline btn-sm" onClick={() => setSelectedSpec('')}>Clear ×</button>
            )}
            <span style={{ color: 'var(--text-muted)', fontSize: 13 }}>{doctors.length} doctor{doctors.length !== 1 ? 's' : ''} found</span>
          </div>
        </div>
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : doctors.length === 0 ? (
        <div className="card"><div className="empty-state">
          <div className="empty-icon">👨‍⚕️</div>
          <h3>No doctors found</h3>
          <p>Try a different specialization</p>
        </div></div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>
          {doctors.map(doc => (
            <div key={doc.id} className="doctor-card" onClick={() => openBooking(doc)}>
              <div style={{ display: 'flex', gap: 14, marginBottom: 14 }}>
                <div className="doctor-avatar">{doc.full_name[0]}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 16 }}>Dr. {doc.full_name}</div>
                  <div style={{ color: 'var(--primary)', fontSize: 13, fontWeight: 500 }}>{doc.specialization}</div>
                  <div style={{ color: 'var(--text-muted)', fontSize: 12, marginTop: 2 }}>{doc.qualification}</div>
                </div>
              </div>

              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 12, fontSize: 13 }}>
                <span>🏥 {doc.hospital_name}</span>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, fontSize: 12, color: 'var(--text-muted)', marginBottom: 14 }}>
                <span>⏱️ {doc.experience_years} yrs exp</span>
                <span>💰 ₹{doc.consultation_fee}</span>
                <span>📅 {doc.available_days}</span>
                <span>🕐 {doc.available_from?.slice(0,5)}–{doc.available_to?.slice(0,5)}</span>
              </div>

              {doc.bio && <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 14, lineHeight: 1.5 }}>{doc.bio}</p>}

              <button className="btn btn-primary btn-block" onClick={(e) => { e.stopPropagation(); openBooking(doc); }}>
                📅 Book Appointment
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Booking Modal */}
      {showModal && selectedDoctor && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal animate-slide" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Book Appointment</h3>
              <button className="modal-close" onClick={() => setShowModal(false)}>×</button>
            </div>
            <div className="modal-body">
              {/* Doctor Info */}
              <div style={{ display: 'flex', gap: 12, padding: 14, background: 'var(--bg)', borderRadius: 10, marginBottom: 20 }}>
                <div className="doctor-avatar" style={{ width: 44, height: 44, fontSize: 18 }}>{selectedDoctor.full_name[0]}</div>
                <div>
                  <div style={{ fontWeight: 700 }}>Dr. {selectedDoctor.full_name}</div>
                  <div style={{ color: 'var(--primary)', fontSize: 13 }}>{selectedDoctor.specialization}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>₹{selectedDoctor.consultation_fee} · {selectedDoctor.hospital_name}</div>
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Select Date *</label>
                <input className="form-control" type="date" min={today} value={selectedDate}
                  onChange={e => handleDateChange(e.target.value)} />
              </div>

              {slotsLoading && <div className="loading-center" style={{ padding: 20 }}><div className="spinner" /></div>}

              {slots.length > 0 && (
                <div className="form-group">
                  <label className="form-label">Select Time Slot *</label>
                  <div className="slots-grid">
                    {slots.map(slot => (
                      <button key={slot.time} className={`slot-btn ${selectedSlot === slot.time ? 'selected' : ''}`}
                        disabled={!slot.available}
                        onClick={() => setSelectedSlot(slot.time)}>
                        {slot.time}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className="form-group">
                <label className="form-label">Reason for Visit</label>
                <textarea className="form-control" rows={3} placeholder="Briefly describe your symptoms or reason..."
                  value={reason} onChange={e => setReason(e.target.value)} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleBook}
                disabled={booking || !selectedDate || !selectedSlot}>
                {booking ? '⏳ Booking...' : '✅ Confirm Booking'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
